1	interface Item {
2	  type: string;
3	}
4	
5	interface QuoteStep {
6	  op: "quote";
7	  items: Item[];
8	}
9	
10	type Step = QuoteStep;
11	
12	interface Scenario {
13	  customer: { yearsWithMHPCO: number };
14	  steps: Step[];
15	}
16	
17	const BASE_PREMIUM: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	};
23	
24	const FIRST_INSURANCE_SURCHARGE = 0.1;
25	const PROCESSING_FEE = 5;
26	
27	// Premiums are rounded up. We strip floating-point noise (e.g. 197.49999999)
28	// before rounding so that arithmetic artefacts don't push the result up a whole Gold.
29	const roundPremiumUp = (amount: number): number => Math.ceil(Number(amount.toFixed(6)));
30	
31	const quotePremium = (items: Item[]): number => {
32	  const itemsPremium = items.reduce(
33	    (sum, item) => sum + BASE_PREMIUM[item.type] * (1 + FIRST_INSURANCE_SURCHARGE),
34	    0
35	  );
36	  return roundPremiumUp(itemsPremium + PROCESSING_FEE);
37	};
38	
39	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
40	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step.items) }));
41	  return { results };
42	};
